name := "Stoll 22";
_<x> := PolynomialRing(Rationals());
f := 82342800*x^6 - 470135160*x^5 + 52485681*x^4 + 2396040466*x^3 + 567207969*x^2 - 985905640*x + 247747600;

C := HyperellipticCurve(f);
Ps := RationalPoints(C:Bound:=500);
Qs := [Ps[i]-Ps[1] : i in [2..#Ps]];



